/* Flow: self_hosted.driver.print_usage */
void fl_self_hosted_driver_print_usage(void) {
    fl_eprintln(fl_string_from_cstr("Usage: driver <subcommand> [options]"));
    fl_eprintln(fl_string_from_cstr(""));
    fl_eprintln(fl_string_from_cstr("Subcommands:"));
    fl_eprintln(fl_string_from_cstr("  compile <source.flow> [-o output] [--stdlib dir]"));
    fl_eprintln(fl_string_from_cstr("  run <source.flow> [--stdlib dir] [-- args...]"));
    fl_eprintln(fl_string_from_cstr("  check <source.flow> [--stdlib dir]"));
    fl_eprintln(fl_string_from_cstr("  emit <source.flow> [-o output.c] [--stdlib dir]"));
}

/* Flow: self_hosted.driver.detect_stdlib_dir */
FL_String* fl_self_hosted_driver_detect_stdlib_dir(void) {
    FL_String* cwd = fl_path_cwd();
    FL_String* stdlib_candidate = fl_path_join(fl_array_push_ptr(fl_array_push_ptr(fl_array_new(0, 0, NULL), cwd), fl_string_from_cstr("stdlib")));
    if (fl_path_exists(stdlib_candidate)) {
        return stdlib_candidate;
    }
    FL_String* parent_stdlib = fl_path_join(fl_array_push_ptr(fl_array_push_ptr(fl_array_new(0, 0, NULL), fl_path_parent(cwd)), fl_string_from_cstr("stdlib")));
    if (fl_path_exists(parent_stdlib)) {
        return parent_stdlib;
    }
    return stdlib_candidate;
}

